@@ -0,0 +1,15 @@
+{
+  "name": "sgr_bright_colors",
+  "description": "SGR 90-97 sets bright foreground (named 8-15), SGR 100-107 sets bright background",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b39316d4a1b5b3130346d4b1b5b306d4c",
+  "comment": "SGR(91) bright red fg (named 9), print J. SGR(104) bright blue bg (named 12), print K. SGR(0) reset, print L.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "J", "attrs": { "fg_color": { "named": 9 } } },
+      { "row": 0, "col": 1, "char": "K", "attrs": { "fg_color": { "named": 9 }, "bg_color": { "named": 12 } } },
+      { "row": 0, "col": 2, "char": "L" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_combined_attrs_colors",
+  "description": "Multiple SGR params in a single sequence: bold + indexed fg + RGB bg combined",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b313b33383b353b3230303b34383b323b31303b32303b33306d4d1b5b306d4e",
+  "comment": "SGR(1;38;5;200;48;2;10;20;30) bold + indexed fg 200 + RGB bg (10,20,30), print M. SGR(0) reset, print N.",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "M", "attrs": { "bold": true, "fg_color": { "indexed": 200 }, "bg_color": { "rgb": [10, 20, 30] } } },
+      { "row": 0, "col": 1, "char": "N" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_double_underline",
+  "description": "SGR 21 enables double underline, SGR 24 resets all underline styles",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b32316d581b5b32346d59",
+  "comment": "SGR(21) double underline, print X. SGR(24) reset underline, print Y. Y should have no underline.",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "X" },
+      { "row": 0, "col": 1, "char": "Y" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "sgr_indexed_boundary",
+  "description": "SGR 38;5;0 (indexed black/min) and SGR 38;5;255 (indexed max) boundary test",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b33383b353b306d411b5b33383b353b3235356d421b5b306d43",
+  "comment": "SGR(38;5;0) indexed 0, print A. SGR(38;5;255) indexed 255, print B. SGR(0) reset, print C.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "fg_color": { "indexed": 0 } } },
+      { "row": 0, "col": 1, "char": "B", "attrs": { "fg_color": { "indexed": 255 } } },
+      { "row": 0, "col": 2, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "sgr_indexed_color_fg_bg",
+  "description": "SGR 38;5;N sets indexed foreground, SGR 48;5;N sets indexed background, SGR 0 resets",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b33383b353b3139366d411b5b34383b353b32326d421b5b306d43",
+  "comment": "SGR(38;5;196) indexed fg 196, print A. SGR(48;5;22) indexed bg 22, print B. SGR(0) reset, print C.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "fg_color": { "indexed": 196 } } },
+      { "row": 0, "col": 1, "char": "B", "attrs": { "fg_color": { "indexed": 196 }, "bg_color": { "indexed": 22 } } },
+      { "row": 0, "col": 2, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "sgr_rgb_truecolor",
+  "description": "SGR 38;2;R;G;B sets RGB foreground, SGR 48;2;R;G;B sets RGB background, SGR 39;49 resets to default",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b33383b323b3235353b3132383b306d441b5b34383b323b303b36343b3132386d451b5b33393b34396d46",
+  "comment": "SGR(38;2;255;128;0) RGB fg, print D. SGR(48;2;0;64;128) RGB bg, print E. SGR(39;49) default fg+bg, print F.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "D", "attrs": { "fg_color": { "rgb": [255, 128, 0] } } },
+      { "row": 0, "col": 1, "char": "E", "attrs": { "fg_color": { "rgb": [255, 128, 0] }, "bg_color": { "rgb": [0, 64, 128] } } },
+      { "row": 0, "col": 2, "char": "F" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "sgr_underline_color",
+  "description": "SGR 58;5;N sets underline color (indexed), SGR 58;2;R;G;B sets underline color (RGB), SGR 59 resets underline color",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b35383b353b3136306d1b5b346d471b5b35383b323b303b3235353b306d481b5b35396d49",
+  "comment": "SGR(58;5;160) indexed underline color + SGR(4) underline on, print G. SGR(58;2;0;255;0) RGB underline color, print H. SGR(59) reset underline color, print I.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "G", "attrs": { "underline": true } },
+      { "row": 0, "col": 1, "char": "H", "attrs": { "underline": true } },
+      { "row": 0, "col": 2, "char": "I", "attrs": { "underline": true } }
+    ]
+  }
+}
